struct Point2D {
    double x;
    double y;
    Point2D(double x_, double y_) : x(x_), y(y_) {}
    double distance(const Point2D& other) const {
        double dx = x - other.x;
        double dy = y - other.y;
        return std::sqrt(dx * dx + dy * dy);
    }
    double norm() const {
        return std::sqrt(x * x + y * y);
    }
};

