struct Accumulator {
    double total;
    int count;
    Accumulator() : total(0.0), count(0) {}
    void add(double value) {
        total = total + value;
        count = count + 1;
    }
    double mean() const {
        if (count == 0) return 0.0;
        return total / (double)count;
    }
};

