struct Accumulator(Copyable, Movable):
    var total: Float64
    var count: Int

    def __init__(out self):
        self.total = 0.0
        self.count = 0

    def add(mut self, value: Float64):
        self.total = self.total + value
        self.count = self.count + 1

    def mean(self) -> Float64:
        if self.count == 0:
            return 0.0
        return self.total / Float64(self.count)

