struct Counter(Copyable, Movable):
    var value: Int
    var step: Int

    def __init__(out self, start: Int, step: Int):
        self.value = start
        self.step = step

    def increment(mut self):
        self.value = self.value + self.step

    def get(self) -> Int:
        return self.value

    def reset(mut self):
        self.value = 0

